class Solution:
    def flipLights(self, n: int, presses: int) -> int:
        if n == 0 or presses == 0:
            return 1
        if n == 1:
            return 2
        if n == 2:
            return 4 if presses >= 2 else 3
        if presses >= 3:
            return 8
        if presses == 2:
            return 7
        return 4
